var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어휴, 멀리서도 탄내가 진동하네. 보나마나 부품은 죄다 교체해야겠어.","JPN":"うわっ、焦げ臭いぞ。\\nこりゃ見るまでもなく部品は全取っ換えだね。","ENG":"Geez, I can smell the burning from here. I bet you’ll have to change all your parts.","TWN":"哇，遠遠的就可以聞到燒焦味，零件應該全都要換了吧！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"어쩔 수 없지. 좋은 경험을 한 대가로 치는 수밖에.","JPN":"仕方ない。高い勉強代だったと考えよう。","ENG":"Oh well. I guess that’s the price I paid for a good lesson.","TWN":"沒辦法，就當作是花錢買經驗吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"나야 직접 안 싸워서 모르겠지만…… 얼마나 강했는데 그래?","JPN":"俺は戦ってないからピンと来ないな……どれだけ強かったんだ？","ENG":"I didn’t have the chance to fight him head on... How strong was he?","TWN":"我是沒有直接參與，所以不太清楚……到底是有多厲害？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"배터리가 폭발할 만큼 아찔한 상대였지. 새로운 심장을 달지 않았으면 죽었을 거다.","JPN":"バッテリーが爆発するほどのとんでもない相手だった。\\n新しい心臓を取り付けてなかったら、とっくにくたばってただろう。","ENG":"Strong enough to blow up my battery. I would have died if it wasn’t for the new heart.","TWN":"厲害到電池會爆炸的程度，要不是有你新替我裝上的心臟，我早就一命嗚呼。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"정말? 시험 삼아 달아 본 건데 진짜 도움이 됐다고?","JPN":"マジかよ。試しに取り付けただけなのに、実際に役に立ったのか？","ENG":"Really? It was just a test, and it actually helped?","TWN":"真的假的？我只是裝好玩的欸，結果真的派上用場啦？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그 남자, 강하더군.","JPN":"あの男、本当に強かった。","ENG":"That man was strong.","TWN":"那男人，很強。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"카운터 중에서도 분명 A급……. 아니, S급일지도 모르겠어.","JPN":"カウンターのなかでもきっとA級……いや、S級かもしれない。","ENG":"He must be a Grade A... no, maybe a Grade S Counter.","TWN":"以制裁者來說應該是A級……不，說不定有到S級。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그보다 수집가는 어디 있지?","JPN":"それより収集家はどこだ？","ENG":"By the way, where is the Collector?","TWN":"話說回來，收藏家人呢？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"평의회랑 교신 중이야. 일이 틀어진 것 때문에 저기압이던데.","JPN":"評議会と交信中だよ。計画が狂ったことでご機嫌ななめだったけど。","ENG":"She’s talking to the Council now. She’s in a bad mood because of what happened.","TWN":"她在和評議會通話中。因為事情搞砸了，氣氛不太好的樣子。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"정황은 이해했어.","JPN":"状況は理解した。","ENG":"I understand the situation now.","TWN":"事情的來龍去脈我都知道了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"갑작스럽게 벌어진 일이라 많이 놀랐겠군. 유감이야.","JPN":"突然のことでさぞ驚いただろうな、残念だ。","ENG":"It was an unexpected accident. I feel for you.","TWN":"事發突然，想必你們應該也受到不少驚嚇，我感到很遺憾。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"여유부릴 때가 아니야. 당장 다른 놈들도 호출해.","JPN":"余裕こいている場合じゃない、今すぐ他の奴らも呼び出せ。","ENG":"This is not the time for comfort. Call the others.","TWN":"現在不是打官腔的時候，趕快找幫手吧！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"음? 어째서?","JPN":"うん？　なぜだ？","ENG":"Hmm? Why?","TWN":"嗯？為什麼？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그걸 몰라서 묻나?","JPN":"そりゃ聞くまでもないだろ。","ENG":"Don’t you see?","TWN":"你是明知故問嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"이쪽에서 대응 못한 건 인정하지. 다른 녀석들까지 체면을 구기게 만든 것도.","JPN":"俺らが対応に失敗したのは認める。他の奴らの面子まで潰したことも。","ENG":"I admit that I failed. I also admit that I made others look bad.","TWN":"我承認我們這次確實是辦事不力，也害其他人的面子掛不住。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"하지만 이럴 때 뒷짐 지고 구경만 하자고 평의회를 만들지는 않았을 텐데?","JPN":"だが、評議会はこんな時に傍観するだけの機関じゃないだろう？","ENG":"But this is the kind of situation where the Council steps in and helps, rather than sitting back and comforting each other.","TWN":"但評議會創立的目的，應該不是要在這種時候袖手旁觀吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"아, 그 일이라면 걱정할 필요 없네. 상대가 나빴으니까.","JPN":"ああ、その件なら心配ない。相手が悪かったのだから。","ENG":"Oh, don’t worry about it. You just picked the wrong person to fight today.","TWN":"喔～你是說那件事嗎？沒什麼好擔心的，都怪對方不好。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};